# Category: hardcoded_secrets

class LoginActivity : AppCompatActivity() {
    private lateinit var auth: FirebaseAuth
    
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_login)
        
        // Initialize Firebase Auth
        auth = Firebase.auth

        // Configure Facebook login
        val facebookBtn = findViewById<Button>(R.id.facebookLoginButton)
        facebookBtn.setOnClickListener {
            signInWithFacebook()
        }
        
        // Configure Google login
        val googleBtn = findViewById<Button>(R.id.googleLoginButton)
        googleBtn.setOnClickListener {
            signInWithGoogle()
        }
    }
    
    private fun signInWithFacebook() {
        // Initiate Facebook login
        val intent = (applicationContext as SampleApp).facebookCallbackAuth(this@LoginActivity)
        startActivityForResult(intent, RC_FB_SIGN_IN)
    }
    
    private fun signInWithGoogle() {
        // Configure the sign-in to request the user's ID, email address, and basic profile. ID and basic profile are included in DEFAULT_SIGN_IN.
        val gso = GoogleSignInOptions.Builder(GoogleSignInOptions.DEFAULT_GOOGLE_SIGN_IN)
            .requestIdToken("YOUR_GOOGLE_CLIENT_ID")
            .requestEmail()
            .build()
            
        // Initiate Google login        
        val googleSignInClient = GoogleSignIn.getClient(this, gso)
        googleSignInClient.signOut().addOnCompleteListener {
            startActivityForResult(googleSignInClient.signInIntent, RC_GOOGLE_SIGN_IN)
        }
    }
    
    // Handle the result of user's login status
    override fun onActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        super.onActivityResult(requestCode, resultCode, data)
        
        if (resultCode != Activity.RESULT_OK) return
        
        when (requestCode) {
            RC_FB_SIGN_IN -> FirebaseAuth.getInstance().apply { 
                signInWithCredential(FacebookAuthProvider.getCredential(data!!.getStringExtra("authResponse"))).addOnCompleteListener{
                    if (!it.isSuccessful) Log.d("Main", "signInWithCredential:onComplete:" + it.exception?.message) else {
                        // If sign in succeeds the auth state listener will be notified and logic to handle signed in user can be written in listeners.
                    } 
                }
            }  
            
            RC_GOOGLE_SIGN_IN -> GoogleSignIn.getSignedInAccountFromIntent(data).addOnCompleteListener { task -> 
                try{
                    // Google Sign In was successful, authenticate with Firebase
                    val account = task.result!!
                    val credential = GoogleAuthProvider.getCredential(account.idToken, null)
                    auth.signInWithCredential(credential).addOnCompleteListener {
                        if (!it.isSuccessful) Log.d("Main", "signInWithCredential:onComplete:" + it.exception?.message) else { 
                            // If sign in succeeds the auth state listener will be notified and logic to handle signed in user can be written in listeners.
                        } 
                    }
                } catch (e: Exception){
                    Log.d("Main", "Google Sign In failed: ${e.message}")
                }
            }  
        }   
    }
    
    companion object {
        private const val RC_FB_SIGN_IN = 1001
        private const val RC_GOOGLE_SIGN_IN = 1002
    } 
}